Title: PubSub.isFull
Category: function
Module Path: effect/PubSub
Export Kind: const
Category Tag: predicates

Description: Returns `true` if the `PubSub` contains at least one element, `false` otherwise.

Signature: isFull = <A>(self: PubSub<A>): Effect.Effect<boolean> => Effect.map(size(self), (size) => size === self.pubsub.capacity)

Example:
```ts
import { Effect } from "effect"
import * as PubSub from "effect/PubSub"

const program = Effect.gen(function*() {
  const pubsub = yield* PubSub.bounded<string>(2)

  // Initially not full
  const initiallyFull = yield* PubSub.isFull(pubsub)
  console.log("Initially full:", initiallyFull) // false

  // Fill the PubSub
  yield* PubSub.publish(pubsub, "msg1")
  yield* PubSub.publish(pubsub, "msg2")

  const nowFull = yield* PubSub.isFull(pubsub)
  console.log("Now full:", nowFull) // true
}

