  yield* Ref.update(counter, (n) => n * 2)

  const value = yield* Ref.get(counter)
  console.log(value) // 2

  // Atomic modify with return value
  const previous = yield* Ref.getAndSet(counter, 100)
  console.log(previous) // 2
})
```

