Title: Cron.next
Category: function
Module Path: effect/Cron
Export Kind: const
Category Tag: utils

Description: Returns the next scheduled date/time for the given Cron instance. This function calculates the next date and time when the cron schedule should trigger, starting from the specified date (or current time if not provided).

Signature: next = (cron: Cron, now?: DateTime.DateTime.Input): Date => { const tz = cron.tz const zoned = dateTime.makeZonedUnsafe(now ?? new Date(), { timeZone: tz })

Example:
```ts
import { Cron, Result } from "effect"

const cron = Result.getOrThrow(Cron.parse("0 0 4 8-14 * *"))

// Get next run after a specific date
const after = new Date("2021-01-01T00:00:00Z")
const nextRun = Cron.next(cron, after)
console.log(nextRun) // 2021-01-08T04:00:00.000Z

// Get next run from current time
const nextFromNow = Cron.next(cron)
console.log(nextFromNow) // Next occurrence from now
```

